{
  "mode": "method",
  "tests": [
    {
      "name": "valid_country_lookup",
      "input": {
        "countryCode": "US"
      },
      "output": {
        "fromDB": true,
        "result": {
          "name": "United States",
          "code": "US"
        }
      },
      "notes": "Valid country lookup should return the correct format and data."
    },
    {
      "name": "valid_device_lookup",
      "input": {
        "deviceId": "12345"
      },
      "output": {
        "fromDB": true,
        "result": {
          "name": "Device A",
          "id": "12345"
        }
      },
      "notes": "Valid device lookup should return the correct format and data."
    },
    {
      "name": "country_lookup_with_unnecessary_fields",
      "input": {
        "countryCode": "CA"
      },
      "output": {
        "fromDB": true,
        "result": {
          "name": "Canada",
          "code": "CA"
        }
      },
      "notes": "Ensure unnecessary fields like createdAt, updatedAt are not included."
    },
    {
      "name": "invalid_country_lookup",
      "input": {
        "countryCode": "ZZ"
      },
      "output": {
        "fromDB": true,
        "result": null
      },
      "notes": "Invalid country code should return null result."
    },
    {
      "name": "swagger_security_mapping",
      "input": {
        "endpoint": "/v6/lookups/countries"
      },
      "output": {
        "secured": false
      },
      "notes": "Public endpoint should not be marked as secured."
    },
    {
      "name": "base_path_check",
      "input": {
        "endpoint": "/v6/lookups/devices"
      },
      "output": {
        "fromDB": true,
        "result": {
          "message": "Endpoint is correctly configured."
        }
      },
      "notes": "Ensure the base path is correctly set for all endpoints."
    },
    {
      "name": "error_handling_format",
      "input": {
        "countryCode": null
      },
      "output": {
        "fromDB": true,
        "result": {
          "error": "Invalid country code."
        }
      },
      "notes": "Error handling should maintain the response format."
    },
    {
      "name": "empty_device_lookup",
      "input": {
        "deviceId": ""
      },
      "output": {
        "fromDB": true,
        "result": null
      },
      "notes": "Empty device ID should return null result."
    }
  ],
  "assumptions": "All endpoints are accessible and the database is properly seeded.",
  "notes": "Ensure all tests validate the required response format and handle edge cases."
}
